TOPICS.update(TERMS)

def build_knowledge_card(topic: str) -> dict:
    key = topic.casefold()
    card = CARDS.get(key, {"simple_explanation":"Тема отсутствует в каталоге.","how_it_works":["Уточните условия у поставщика."],"key_risks":["Недостаточно данных."],"what_to_check":["Запросите официальный документ."],"common_misunderstandings":["Маркетинговые формулировки не равны полным условиям."]})
    return {"title": key, **card, "not_advice_disclaimer": "Сервис не даёт индивидуальные инвестиционные рекомендации."}
